vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_fc_main, vUv ).xyz*.8;
    ret += GetBlur1(vUv)*.2;

    // darken (decay) over uTime and distance from center
    ret *= ret/(1.4*vRadius); //or try: ret -= 0.004;

